// Build Response Code
// Simple heuristic extraction only (no LLM).
// Detect: problem, city, language, therapy_type. Empty string if not detected.
// Keep response schema stable: { assistant_message, result: { top5, reasons, extraction } }

function clean(s) {
  return (s ?? '').toString().replace(/\s+/g, ' ').trim();
}

function lower(s) {
  return clean(s).toLowerCase();
}

function uniqNonEmpty(arr) {
  const out = [];
  const seen = new Set();
  for (const v of (arr ?? [])) {
    const c = clean(v);
    if (!c) continue;
    const k = c.toLowerCase();
    if (seen.has(k)) continue;
    seen.add(k);
    out.push(c);
  }
  return out;
}

const input = $input.first().json;
const body = input.body ?? input;

// From backend payload: { message, available_therapists, conversation, ... }
const message = clean(body.message ?? body.text ?? body.user_message ?? input.message ?? input.text);
const mL = lower(message);

const extraction = {
  problem: '',
  city: '',
  language: '',
  therapy_type: '',
};

// ---------------- language ----------------
const languagePatterns = [
  { value: 'Hebrew', re: /\b(hebrew|ivrit)\b|עברית/iu },
  { value: 'English', re: /\benglish\b|אנגלית/iu },
  { value: 'Russian', re: /\brussian\b|רוסית/iu },
  { value: 'Arabic', re: /\barabic\b|ערבית/iu },
  { value: 'French', re: /\bfrench\b|צרפתית/iu },
  { value: 'Spanish', re: /\bspanish\b|ספרדית/iu },
];
for (const p of languagePatterns) {
  if (p.re.test(message)) {
    extraction.language = p.value;
    break;
  }
}

// ---------------- therapy_type ----------------
const therapyTypePatterns = [
  { value: 'CBT', re: /\bcbt\b|קוגניטיבי\s*התנהגותי|סי\s*בי\s*טי/iu },
  { value: 'DBT', re: /\bdbt\b|דב"?ט/iu },
  { value: 'EMDR', re: /\bemdr\b|אי\s*אם\s*די\s*אר/iu },
  { value: 'ACT', re: /\bact\b|\bacceptance\s+and\s+commitment\b|אקט/iu },
  { value: 'Couples', re: /\b(couples|couple|marriage)\b|טיפול\s*זוגי/iu },
  { value: 'Family', re: /\bfamily\b|טיפול\s*משפחתי/iu },
  { value: 'Group', re: /\bgroup\b|טיפול\s*קבוצתי/iu },
  { value: 'Psychodynamic', re: /\bpsychodynamic\b|פסיכודינמי/iu },
];
for (const p of therapyTypePatterns) {
  if (p.re.test(message)) {
    extraction.therapy_type = p.value;
    break;
  }
}

// ---------------- city ----------------
// Prefer matching a city that exists in the therapists list (simple & accurate).
const cities = uniqNonEmpty((body.available_therapists ?? []).map(t => t?.city));
// Try longer city names first to avoid partial matches
cities.sort((a, b) => b.length - a.length);

for (const c of cities) {
  const cL = c.toLowerCase();
  if (cL && mL.includes(cL)) {
    extraction.city = c;
    break;
  }
}

// Fallback (English): "in <City>" / "near <City>" / "around <City>"
if (!extraction.city) {
  const m = message.match(/\b(?:in|near|around|at)\s+([A-Z][A-Za-z'\-]+(?:\s+[A-Z][A-Za-z'\-]+){0,2})\b/);
  if (m) extraction.city = clean(m[1]);
}

// ---------------- problem ----------------
// Try explicit request patterns first
{
  const m = message.match(/\b(?:help|therapy|therapist|looking\s+for)\b[^\n\.]{0,50}\b(?:for|with)\b\s+([^\n\.;]{3,140})/i);
  if (m) extraction.problem = clean(m[1]);
}

// Keyword-based fallback (structured)
if (!extraction.problem) {
  const keywords = [
    { value: 'Anxiety', re: /\banxiety\b|חרדה/iu },
    { value: 'Depression', re: /\bdepression\b|דיכאון/iu },
    { value: 'Stress', re: /\bstress\b|לחץ/iu },
    { value: 'Burnout', re: /\bburnout\b|שחיקה/iu },
    { value: 'Panic attacks', re: /\bpanic\b|פאניקה/iu },
    { value: 'OCD', re: /\bocd\b|אובסס/iu },
    { value: 'ADHD', re: /\badhd\b|קשב\s*וריכוז|הפרעת\s*קשב/iu },
    { value: 'Trauma', re: /\btrauma\b|\bptsd\b|טראומה/iu },
    { value: 'Grief', re: /\bgrief\b|אבל/iu },
    { value: 'Relationship', re: /\brelationship\b|זוגיות/iu },
    { value: 'Sleep', re: /\binsomnia\b|\bsleep\b|שינה/iu },
    { value: 'Self-esteem', re: /self\s*-?esteem|דימוי\s*עצמי/iu },
  ];

  const hits = [];
  for (const k of keywords) {
    if (k.re.test(message)) hits.push(k.value);
  }
  if (hits.length) extraction.problem = hits.slice(0, 2).join(', ');
}

// assistant_message must use extracted values
const assistant_message =
  'Extracted request: ' +
  'problem=' + (extraction.problem || '') + ' ' +
  'city=' + (extraction.city || '') + ' ' +
  'language=' + (extraction.language || '') + ' ' +
  'therapy_type=' + (extraction.therapy_type || '');

return [
  {
    json: {
      assistant_message,
      result: {
        top5: [],
        reasons: [],
        extraction,
      },
    },
  },
];
